cd /tmp/sv-a2f3b8d66c16498c8ee90a888fe1df05/moderate-msbuild-properties && dotnet package list --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: (project_basename, package_id) -> resolvedVersion
def build_lookup(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].rsplit('/', 1)[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv == av:
        unchanged.append(k + (bv,))
    else:
        changes.append(k + (bv, av))

if changes:
    print('CHANGES:')
    for proj, pkg, bv, av in changes:
        print(f'  {proj} | {pkg} | {bv} -> {av}')
else:
    print('NO CHANGES - conversion is fully version-neutral')
print()
print('UNCHANGED:')
for proj, pkg, v in unchanged:
    print(f'  {proj} | {pkg} | {v}')
"

